let incode,session;const container=document.getElementById("incode-container");async function init(){const e=await fetch("https://your-backend.com/create-session");session=await e.json(),incode=await window.OnBoarding.create({apiURL:"https://demo-api.incodesmile.com/0"}),await sendGeo()}async function sendGeo(){await incode.sendGeolocation({token:session.token}).catch(console.error),renderID()}function renderID(){incode.renderCaptureId(container,{token:session,onSuccess:renderFace,onError:console.error})}function renderFace(){incode.renderCaptureFace(container,{token:session,onSuccess:doFaceMatch,onError:console.error})}async function doFaceMatch(){await incode.processFace({token:session.token}),await incode.finishOnboarding({token:session.token}),await fetch(`https://your-backend.com/complete?token=${session.token}`)}document.addEventListener("DOMContentLoaded",init);